UPDATE VISIT_ITEM
SET VISIT_ORDER = #{visitOrder}, DISTANCE_TO_NEXT = #{distanceToNext}
WHERE VISIT_ITEM_ID = #{visitItemId}

UPDATE MY_SCHEDULE
SET TITLE = #{scheduleTitle}, START_AT = #{startAt},
    BUDGET_DETAILS = #{budgetDetail}, TODO_DETAILS = #{todoDetail}, IS_SHARED = #{isShared}
WHERE MY_SCHEDULE_ID = #{scheduleId} AND USER_ID = #{userId}

mapper.insert:
INSERT INTO SCHEDULE_POST
    (POST_ID, TITLE, BUDGET_DETAILS, TODO_DETAILS, IS_ANONYMOUS, VIEW_COUNT, LIKE_COUNT, POSTED_AT, USER_ID)
SELECT ('P' || LPAD(SEQ_SCHEDULE_POST.NEXTVAL, 3, '0')),
       TITLE, BUDGET_DETAILS, TODO_DETAILS, #{isAnonymous}, 0, 0, SYSDATE, #{userId}
FROM MY_SCHEDULE WHERE MY_SCHEDULE_ID = #{myScheduleId}

mapper.select:
SELECT MY_SCHEDULE_ID, TITLE
FROM MY_SCHEDULE WHERE USER_ID = #{userId}
ORDER BY START_AT DESC, MY_SCHEDULE_ID DESC
